+/// Write a u8 as decimal digits to a writer without formatting overhead.
+#[inline]
+fn write_u8_decimal(w: &mut impl Write, n: u8) -> io::Result<()> {
+    if n >= 100 {
+        w.write_all(&[b'0' + n / 100, b'0' + (n / 10) % 10, b'0' + n % 10])
+    } else if n >= 10 {
+        w.write_all(&[b'0' + n / 10, b'0' + n % 10])
+    } else {
+        w.write_all(&[b'0' + n])
+    }
+}
